def _mark_payment_creation_failed(payment_id: int, provider: str, reason: str = "") -> None:
    """Move a locally-created payment out of pending when provider invoice/order creation failed."""
    try:
        with get_conn() as conn:
            conn.execute(
                "UPDATE payments SET status='payment_creation_failed', admin_note=?, approved_at=? "
                "WHERE id=? AND payment_method=? AND status='pending'",
                ((reason or "payment creation failed")[:500], now_str(), payment_id, provider),
            )
    except Exception as exc:
        log.warning("payment_creation_failed update failed payment_id=%s provider=%s: %s", payment_id, provider, exc)


# ── OpenVPN helpers (shared with messages.py) ─────────────────────────────────

def _verify_tronado_payment(payment_id: int) -> dict:
    """
    Shared Tronado verification used by all :verify: handlers.
    The central processor reads the exact payment row, extracts its own token,
    verifies Tronado, locks atomically, and fulfills at most once.
    """
    proc = process_tronado_verified_payment(
        payment_id,
        source="manual_verify",
        raw_payload={"manual_verify": True, "payment_id": payment_id},
    )
    status = proc.get("status", "process_error")
    if status == "ok":
        return {"verify": "ok", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}
    if status == "already_processed":
        return {"verify": "already_processed", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}
    if status == "pending":
        return {"verify": "pending", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}
    if status == "rejected":
        return {"verify": "rejected", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}
    if status == "expired":
        return {"verify": "expired", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}
    return {"verify": "process_error", "process_result": proc, "raw_resp": proc.get("raw_resp", {})}


def _verify_centralpay_payment(payment_id: int) -> dict:
    """
    Shared CentralPay payment verification used by all :verify: handlers.
    Calls process_centralpay_verified_payment which atomically locks and verifies.

    Returns dict with:
      "verify": "ok" | "already_processed" | "not_paid" | "process_error" | "amount_mismatch"
      "process_result": dict from process_centralpay_verified_payment (or {})
    """
    from ..crypto_fulfillment import process_centralpay_verified_payment
    proc = process_centralpay_verified_payment(payment_id, source="manual_verify", raw_payload=None)
    status = proc.get("status", "")
    if status == "ok":
        return {"verify": "ok", "process_result": proc}
    if status == "already_processed":
        return {"verify": "already_processed", "process_result": proc}
    if status == "amount_mismatch":
        return {"verify": "amount_mismatch", "process_result": proc}
    if status == "user_mismatch":
        return {"verify": "user_mismatch", "process_result": proc}
    if status == "not_paid":
        return {"verify": "not_paid", "process_result": proc}
    if status == "expired":
        return {"verify": "expired", "process_result": proc}
    return {"verify": "process_error", "process_result": proc}


def _fmt_users_label(max_users):
    if not max_users or max_users == 0:
        return "نامحدود"
    if max_users == 1:
        return "تک‌کاربره"
    if max_users == 2:
        return "دوکاربره"
    return f"{max_users} کاربره"


# ── V2Ray helpers ─────────────────────────────────────────────────────────────

def _v2_name_from_sub(sub_url: str) -> str:
    """Extract service name from the last path segment of a subscription URL.

    Example:
        http://s1.example.xyz:2096/sub/n1lw9my64qykgz4n → n1lw9my64qykgz4n
    """
    if not sub_url:
        return "sub"
    try:
        path = urllib.parse.urlparse(sub_url.strip()).path
        segments = [s for s in path.split("/") if s]
        return segments[-1] if segments else "sub"
    except Exception:
        return (sub_url.rsplit("/", 1)[-1] or "sub")


def _v2_name_from_vmess(cfg_text: str) -> str:
    """Extract the 'ps' (presentation name) field from a VMess base64 config.
    Falls back to host:port or 'VMess Config' on any error.
    """
    import base64, json as _json
    try:
        # Strip vmess:// prefix and any trailing #tag
        body = cfg_text[8:].split("#")[0]
        # Pad to multiple of 4
        padded = body + "=" * (-len(body) % 4)
        data = _json.loads(base64.b64decode(padded).decode("utf-8"))
        ps = (data.get("ps") or "").strip()
        if ps:
            return ps
        host = (data.get("add") or data.get("host") or "").strip()
        port = str(data.get("port", "")).strip()
        return f"{host}:{port}" if host else "VMess Config"
    except Exception:
        return "VMess Config"


def _v2_name_from_config(cfg_text: str, prefix: str = "", suffix: str = "") -> str:
    """Extract and clean service name from a V2Ray config's URL-encoded #tag.

    For vmess:// configs that lack a #tag, decodes the base64 JSON and uses
    the 'ps' field (then host:port) as name.
    """
    # VMess special handling: decode base64 JSON for the ps field
    if cfg_text.startswith("vmess://"):
        if "#" not in cfg_text:
            return _v2_name_from_vmess(cfg_text)
        # Has a #tag — use the tag (normal path below), but fall back to ps if empty
        raw_tag = cfg_text.rsplit("#", 1)[1].strip()
        if not raw_tag:
            return _v2_name_from_vmess(cfg_text)

    if "#" in cfg_text:
        raw = cfg_text.rsplit("#", 1)[1]
    else:
        return "config"
    try:
        name = urllib.parse.unquote(raw)
    except Exception:
        name = raw
    # Strip prefix
    if prefix:
        if name.startswith(prefix):
            name = name[len(prefix):]
        try:
            dp = urllib.parse.unquote(prefix)
            if dp != prefix and name.startswith(dp):
                name = name[len(dp):]
        except Exception:
            pass
    # Strip suffix
    if suffix:
        if name.endswith(suffix):
            name = name[:-len(suffix)]
        try:
            ds = urllib.parse.unquote(suffix)
            if ds != suffix and name.endswith(ds):
                name = name[:-len(ds)]
        except Exception:
            pass
    return name.strip().strip("-").strip("_").strip() or "config"


