def _execute_pnlcfg_renewal(config_id, package_id, chat_id=None, uid=None):
    """
    Execute panel config renewal: ADD volume + time to existing client (no reset).
    The package's volume_gb and duration_days are added on top of current values.
    Retries indefinitely on connection errors (up to 8 hours).
    On non-connection failures retries up to 3 minutes then gives up.
    Returns (True, None) on success or (False, user_friendly_msg) on fatal failure.
    Admins are notified via _notify_panel_error on any fatal failure.
    """
    import time as _time
    from ..db import get_panel_config as _get_pcfg, update_panel_config_field as _upf
    from ..db import get_panel as _get_pnl, get_package as _get_pkg3
    from ..panels.client import PanelClient
    from datetime import datetime as _dt, timedelta as _td

    cfg = _get_pcfg(config_id)
    if not cfg:
        return False, "کانفیگ یافت نشد."
    cfg = dict(cfg)
    _uid = uid or cfg["user_id"]
    pkg = _get_pkg3(package_id)
    if not pkg:
        return False, "پکیج یافت نشد."
    panel = _get_pnl(cfg["panel_id"])
    if not panel:
        return False, "پنل یافت نشد."

    pc_api = PanelClient(
        protocol=panel["protocol"], host=panel["host"], port=panel["port"],
        path=panel["path"] or "", username=panel["username"], password=panel["password"]
    )

    def _is_conn_err(e):
        s = str(e).lower()
        return any(x in s for x in [
            "connection refused", "max retries exceeded", "failed to establish",
            "newconnectionerror", "httpsconnectionpool", "remotedisconnected",
            "connection timed out", "read timed out", "timeout",
            "connection reset", "connection aborted", "connectionreseterror",
            "econnreset", "broken pipe", "reset by peer",
        ])

    # Quick-retry mode: 3 attempts × 20 seconds. If all fail, return an error
    # immediately — the caller handles user notification and queuing.
    QUICK_MAX_ATTEMPTS = 3
    QUICK_RETRY_DELAY  = 20   # seconds between attempts

    # ── Step 1: login ─────────────────────────────────────────────────────────
    login_err = None
    for _attempt in range(QUICK_MAX_ATTEMPTS):
        if _attempt > 0:
            _time.sleep(QUICK_RETRY_DELAY)
        ok, login_err = pc_api.login()
        if ok:
            login_err = None
            break
        log.warning("_execute_pnlcfg_renewal: login attempt %d/%d failed: %s",
                    _attempt + 1, QUICK_MAX_ATTEMPTS, login_err)
    if login_err is not None:
        _notify_panel_error(_uid, pkg, "login (تمدید)", login_err, config_id, cfg["panel_id"])
        return False, "تمدید سرویس با خطا مواجه شد. لطفاً با پشتیبانی ارتباط بگیرید."

    extra_gb   = float(pkg["volume_gb"] or 0)
    extra_days = int(pkg["duration_days"] or 0)
    # volume_gb==0 means unlimited in 3x-ui (totalGB=0)
    # duration_days==0 means unlimited (expiryTime=0)
    pkg_unlimited_vol  = (extra_gb == 0)
    pkg_unlimited_time = (extra_days == 0)

    new_exp_ms  = None
    new_exp_str = None

    # ── Step 2: Volume ────────────────────────────────────────────────────────
    vol_err = None
    for _attempt in range(QUICK_MAX_ATTEMPTS):
        if _attempt > 0:
            _time.sleep(QUICK_RETRY_DELAY)
        if pkg_unlimited_vol:
            ok_v, res_v = pc_api._update_client(
                cfg["inbound_id"], cfg["client_uuid"], {"totalGB": 0}
            )
        else:
            ok_v, res_v = pc_api.add_client_volume(
                cfg["inbound_id"], cfg["client_uuid"], extra_gb
            )
        if ok_v:
            vol_err = None
            break
        vol_err = str(res_v)
        log.warning("_execute_pnlcfg_renewal: volume attempt %d/%d failed: %s",
                    _attempt + 1, QUICK_MAX_ATTEMPTS, vol_err)
    if vol_err is not None:
        _notify_panel_error(_uid, pkg, "volume (تمدید)", vol_err, config_id, cfg["panel_id"])
        return False, "تمدید سرویس با خطا مواجه شد. لطفاً با پشتیبانی ارتباط بگیرید."

    # ── Step 3: Time ──────────────────────────────────────────────────────────
    time_err = None
    for _attempt in range(QUICK_MAX_ATTEMPTS):
        if _attempt > 0:
            _time.sleep(QUICK_RETRY_DELAY)
        if pkg_unlimited_time:
            ok_t, res_t = pc_api._update_client(
                cfg["inbound_id"], cfg["client_uuid"], {"expiryTime": 0}
            )
            if ok_t:
                new_exp_ms = 0
        else:
            ok_t, res_t = pc_api.add_client_time(
                cfg["inbound_id"], cfg["client_uuid"], extra_days
            )
            if ok_t:
                new_exp_ms = res_t
        if ok_t:
            time_err = None
            break
        time_err = str(res_t)
        log.warning("_execute_pnlcfg_renewal: time attempt %d/%d failed: %s",
                    _attempt + 1, QUICK_MAX_ATTEMPTS, time_err)
    if time_err is not None:
        _notify_panel_error(_uid, pkg, "time (تمدید)", time_err, config_id, cfg["panel_id"])
        return False, "تمدید سرویس با خطا مواجه شد. لطفاً با پشتیبانی ارتباط بگیرید."

    if new_exp_ms:
        import datetime as _datetime
        new_exp_str = _datetime.datetime.utcfromtimestamp(new_exp_ms / 1000).strftime("%Y-%m-%d %H:%M:%S")

    # ── Step 4: enable client (in case it was disabled/expired) ───────────────
    enable_err = None
    for _attempt in range(QUICK_MAX_ATTEMPTS):
        if _attempt > 0:
            _time.sleep(QUICK_RETRY_DELAY)
        ok_e, res_e = pc_api.enable_client(
            inbound_id=cfg["inbound_id"], client_uuid=cfg["client_uuid"],
            email=cfg["client_name"] or "",
        )
        if ok_e:
            enable_err = None
            break
        enable_err = str(res_e)
        log.warning("_execute_pnlcfg_renewal: enable_client attempt %d/%d failed: %s",
                    _attempt + 1, QUICK_MAX_ATTEMPTS, enable_err)
    if enable_err is not None:
        _notify_panel_error(_uid, pkg, "enable_client (تمدید)", enable_err, config_id, cfg["panel_id"])
        return False, "تمدید سرویس با خطا مواجه شد. لطفاً با پشتیبانی ارتباط بگیرید."

    # ── Step 5: update DB ──────────────────────────────────────────────────────
    if pkg_unlimited_time:
        _upf(config_id, "expire_at", "")   # blank = unlimited
    elif new_exp_str:
        _upf(config_id, "expire_at", new_exp_str)
    _upf(config_id, "is_expired",  0)
    _upf(config_id, "is_disabled", 0)
    if int(pkg["id"]) != int(cfg.get("package_id") or 0):
        _upf(config_id, "package_id", pkg["id"])
    return True, None


def _execute_pnlcfg_delete(config_id, chat_id, uid, admin_id):
    """
    Execute panel config deletion in background:
      1. Try to delete from panel (with retry for connection errors, up to 3 min)
      2. ALWAYS delete from DB regardless of panel result
      3. Notify admin of result
    """
    import time as _time
    from ..db import get_panel_config as _get_pcfg, delete_panel_config as _del_pcfg
    from ..db import get_panel as _get_pnl
    from ..panels.client import PanelClient

    cfg = _get_pcfg(config_id)
    if not cfg:
        try:
            bot.send_message(admin_id, "❌ کانفیگ یافت نشد (حذف لغو شد).", parse_mode="HTML")
        except Exception:
            pass
        return

    cfg = dict(cfg)
    client_name = cfg.get("client_name") or "—"
    panel = _get_pnl(cfg["panel_id"])

    CONN_RETRY_DELAY   = 20
    FUNC_RETRY_TIMEOUT = 180   # 3 minutes max for non-connection errors
    FUNC_RETRY_DELAY   = 10
    MAX_WAIT           = 28800  # 8 h for connection errors

    _t_start          = _time.time()
    _waiting_notified = False

    def _is_conn_err(e):
        s = str(e).lower()
        return any(x in s for x in [
            "connection refused", "max retries exceeded", "failed to establish",
            "newconnectionerror", "httpsconnectionpool", "remotedisconnected",
            "connection timed out", "read timed out", "timeout",
            "connection reset", "connection aborted", "connectionreseterror",
            "econnreset", "broken pipe", "reset by peer",
        ])

    # ── Step 1: Delete from panel (if panel info available) ──────────────────
    panel_del_ok  = False
    panel_del_err = None

    if panel and cfg.get("client_uuid") and cfg.get("inbound_id"):
        pc_api = PanelClient(
            protocol=panel["protocol"], host=panel["host"], port=panel["port"],
            path=panel["path"] or "", username=panel["username"], password=panel["password"]
        )

        _t0 = _time.time()
        while True:
            elapsed = _time.time() - _t0

            # Try delete directly (PanelClient._api_call handles login internally)
            try:
                ok_d, err_d = pc_api.delete_client(cfg["inbound_id"], cfg["client_uuid"])
            except Exception as _exc:
                ok_d, err_d = False, str(_exc)

            if ok_d:
                panel_del_ok  = True
                panel_del_err = None
                break

            panel_del_err = str(err_d or "خطای ناشناخته")

            # Connection error → keep retrying (up to 8 h)
            if _is_conn_err(panel_del_err):
                if _time.time() - _t_start > MAX_WAIT:
                    break
                if not _waiting_notified:
                    try:
                        bot.send_message(
                            admin_id,
                            "⏳ <b>پنل در دسترس نیست</b>\n\n"
                            f"حذف کانفیگ <b>{esc(client_name)}</b> در صف انتظار است.\n"
                            "به محض اتصال، حذف انجام می‌شود.",
                            parse_mode="HTML",
                        )
                        _waiting_notified = True
                    except Exception:
                        pass
                log.warning("_execute_pnlcfg_delete: conn error, retry in %ds: %s",
                            CONN_RETRY_DELAY, panel_del_err)
                _time.sleep(CONN_RETRY_DELAY)
                continue

            # Non-connection error → retry for up to FUNC_RETRY_TIMEOUT
            log.warning("_execute_pnlcfg_delete: panel error (%.0fs): %s", elapsed, panel_del_err)
            if elapsed + FUNC_RETRY_DELAY >= FUNC_RETRY_TIMEOUT:
                break
            _time.sleep(FUNC_RETRY_DELAY)

        if panel_del_ok and _waiting_notified:
            try:
                bot.send_message(admin_id, "✅ اتصال به پنل برقرار شد، کانفیگ حذف شد.",
                                 parse_mode="HTML")
            except Exception:
                pass

        if not panel_del_ok:
            _notify_panel_error(uid, None, "delete_client (حذف کانفیگ)", panel_del_err, config_id, cfg["panel_id"])
            try:
                bot.send_message(
                    admin_id,
                    f"⚠️ <b>حذف از پنل ناموفق بود</b>\n\n"
                    f"🔮 سرویس: <b>{esc(client_name)}</b>\n"
                    f"⚠️ خطا: <code>{esc(panel_del_err[:300])}</code>\n\n"
                    "کانفیگ از <b>دیتابیس ربات</b> حذف می‌شود.\n"
                    "لطفاً به صورت دستی از پنل حذف کنید.",
                    parse_mode="HTML",
                )
            except Exception:
                pass
    elif not cfg.get("client_uuid"):
        # Config was never provisioned to the panel (no UUID) — DB-only delete
        panel_del_ok = True   # nothing to delete from panel

    # ── Step 2: ALWAYS delete from DB ────────────────────────────────────────
    _del_pcfg(config_id)

    # ── Step 3: Notify admin ──────────────────────────────────────────────────
    if panel_del_ok:
        try:
            bot.send_message(
                admin_id,
                f"✅ <b>کانفیگ با موفقیت حذف شد</b>\n\n"
                f"🔮 سرویس: <b>{esc(client_name)}</b>",
                parse_mode="HTML",
            )
        except Exception:
            pass
    else:
        try:
            bot.send_message(
                admin_id,
                f"🗑 کانفیگ <b>{esc(client_name)}</b> از دیتابیس ربات حذف شد.\n"
                "(حذف از پنل ناموفق بود — پیام خطا در بالا را ببینید)",
                parse_mode="HTML",
            )
        except Exception:
            pass


