        # ── Buyer role enforcement ────────────────────────────────────────────
        buyer_role = package_row["buyer_role"] if "buyer_role" in package_row.keys() else "all"
        if buyer_role == "nobody":
            bot.answer_callback_query(call.id,
                "🔒 این پکیج در دسترس عموم نیست.",
                show_alert=True)
            return
        if buyer_role != "all":
            _user = get_user(uid)
